import React, { useCallback, useEffect, useMemo, useState } from 'react';
import {
  Card,
  StatsCard,
  StatsCardsGrid,
  TableCard,
  Button,
} from '@linm-soft-org/linm-web-common-components';
import {
  LoadingOverlay,
  AlertBanner,
} from '@/components/common';
import * as XLSX from 'xlsx';
import {
  Bar,
  BarChart,
  CartesianGrid,
  Legend,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from 'recharts';
import { fpcService } from '../../../services/fpc/service';
import type { ThirteenWeekCashflowDto, WeeklyCashflowDto } from '../../../services/fpc/types';
import styles from './ThirteenWeekCashflowPage.module.css';

const TEST_ID = 'thirteen-week';

const fVnd = (v: number): string =>
  new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND', maximumFractionDigits: 0 }).format(v);

const fVndCompact = (v: number): string => {
  if (v >= 1_000_000_000) return `${(v / 1_000_000_000).toFixed(1)} tỷ`;
  if (v >= 1_000_000) return `${(v / 1_000_000).toFixed(1)} tr`;
  return fVnd(v);
};

const fDate = (iso: string): string => {
  try {
    return new Date(iso).toLocaleDateString('vi-VN', { day: '2-digit', month: '2-digit', year: 'numeric' });
  } catch { return iso; }
};

const ThirteenWeekCashflowPage: React.FC = () => {
  const [data, setData] = useState<ThirteenWeekCashflowDto | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [exporting, setExporting] = useState(false);

  useEffect(() => {
    let cancelled = false;
    const load = async () => {
      setLoading(true);
      setError(null);
      try {
        const result = await fpcService.get13WeekReport({});
        if (!cancelled) setData(result);
      } catch (err: unknown) {
        if (!cancelled) setError(err instanceof Error ? err.message : 'Không thể tải dữ liệu');
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    load();
    return () => { cancelled = true; };
  }, []);

  // ── Handle export Excel ──
  const handleExport = useCallback(() => {
    if (!data) return;
    setExporting(true);
    try {
      const rows = data.weeks.map(w => ({
        'Tuần': w.label,
        'Đầu kỳ': w.openingBalance,
        'Thu hoạt động': w.operatingInflow,
        'Chi hoạt động': w.operatingOutflow,
        'Đầu tư': w.investingOutflow,
        'TC': w.financingInflow,
        'Dòng tiền thuần': w.netCashflow,
        'Cuối kỳ': w.closingBalance,
        'Khoảng trống': w.fundingGap > 0 ? w.fundingGap : '',
      }));
      rows.push({
        'Tuần': 'Tổng',
        'Đầu kỳ': data.totalOpening,
        'Thu hoạt động': 0,
        'Chi hoạt động': 0,
        'Đầu tư': 0,
        'TC': 0,
        'Dòng tiền thuần': 0,
        'Cuối kỳ': 0,
        'Khoảng trống': 0,
      });
      const sheet = XLSX.utils.json_to_sheet(rows);
      const book = XLSX.utils.book_new();
      XLSX.utils.book_append_sheet(book, sheet, '13Tuan');
      const stamp = new Date().toISOString().slice(0, 10);
      XLSX.writeFile(book, `dong-tien-13-tuan-${stamp}.xlsx`);
    } finally {
      setExporting(false);
    }
  }, [data]);

  const summaryCards = useMemo(() => {
    if (!data) return null;
    return (
      <StatsCardsGrid columns={4}>
        <StatsCard label="Số dư đầu kỳ" value={fVndCompact(data.totalOpening)} icon="fas fa-coins" variant="info" />
        <StatsCard label="Dòng tiền HĐ 13 tuần" value={fVndCompact(data.totalOperatingNet)} icon="fas fa-chart-line" variant={data.totalOperatingNet >= 0 ? 'success' : 'danger'} />
        <StatsCard label="Đầu tư 13 tuần" value={fVndCompact(data.totalInvestingOutflow)} icon="fas fa-building" variant="warning" />
        <StatsCard label="Số dư cuối 13 tuần" value={fVndCompact(data.closingAfter13Weeks)} icon="fas fa-piggy-bank" variant={data.closingAfter13Weeks >= 0 ? 'success' : 'danger'} />
      </StatsCardsGrid>
    );
  }, [data]);

  const weeklyTable = useMemo(() => {
    if (!data) return null;
    const columns = [
      { header: 'Tuần', accessor: (r: WeeklyCashflowDto) => r.label },
      { header: 'Đầu kỳ', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.openingBalance) },
      { header: 'Thu hoạt động', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.operatingInflow) },
      { header: 'Chi hoạt động', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.operatingOutflow) },
      { header: 'Đầu tư', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.investingOutflow) },
      { header: 'Tài chính', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.financingInflow) },
      { header: 'Dòng tiền thuần', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.netCashflow) },
      { header: 'Cuối kỳ', accessor: (r: WeeklyCashflowDto) => fVndCompact(r.closingBalance) },
      { header: 'Khoảng trống', accessor: (r: WeeklyCashflowDto) => r.fundingGap > 0 ? fVndCompact(r.fundingGap) : '—' },
    ];

    return (
      <TableCard tableCardTestId={`${TEST_ID}-table`}>
        <table className={styles.table}>
          <thead>
            <tr>
              {columns.map(c => <th key={c.header}>{c.header}</th>)}
            </tr>
          </thead>
          <tbody>
            {data.weeks.map((row, i) => (
              <tr key={i} className={row.fundingGap > 0 ? styles.gapRow : ''}>
                {columns.map(c => <td key={c.header}>{c.accessor(row)}</td>)}
              </tr>
            ))}
          </tbody>
          <tfoot>
            <tr className={styles.totalRow}>
              <td>Tổng</td>
              <td>{fVndCompact(data.totalOpening)}</td>
              <td colSpan={9} />
            </tr>
          </tfoot>
        </table>
      </TableCard>
    );
  }, [data]);

  const chart = useMemo(() => {
    if (!data) return null;
    return (
      <Card padding="md" data-testid={`${TEST_ID}-chart`}>
        <h3 className={styles.chartTitle}>Dòng tiền 13 tuần — Thu / Chi / Cuối kỳ</h3>
        <ResponsiveContainer width="100%" height={320}>
          <BarChart data={data.weeks.map(w => ({
            label: `W${w.weekNumber}`,
            inflow: w.operatingInflow,
            outflow: w.operatingOutflow,
            closing: w.closingBalance,
          }))}>
            <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
            <XAxis dataKey="label" tick={{ fontSize: 11 }} />
            <YAxis tickFormatter={v => `${(Number(v) / 1e6).toFixed(0)}M`} tick={{ fontSize: 11 }} />
            <Tooltip formatter={(v: number) => fVnd(v)} />
            <Legend />
            <Bar dataKey="inflow" name="Thu" fill="#52c41a" radius={[3, 3, 0, 0]} />
            <Bar dataKey="outflow" name="Chi" fill="#fa8c16" radius={[3, 3, 0, 0]} />
            <Bar dataKey="closing" name="Cuối kỳ" fill="#1677ff" radius={[3, 3, 0, 0]} />
          </BarChart>
        </ResponsiveContainer>
      </Card>
    );
  }, [data]);

  if (loading) return <LoadingOverlay visible tip="Đang tải dữ liệu dòng tiền 13 tuần..." />;

  if (error) {
    return (
      <div className={styles.page}>
        <AlertBanner type="error" message={error} />
      </div>
    );
  }

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}>
            <i className="fas fa-chart-bar" />
            Dự báo dòng tiền 13 tuần
          </h1>
          <p className={styles.subtitle}>
            Tổng quan dòng tiền hoạt động, đầu tư và tài chính trong 13 tuần tới
            {data ? ` — cập nhật: ${fDate(data.asOfDate)}` : ''}
          </p>
        </div>
        <div className={styles.headerActions}>
          <Button
            variant="secondary"
            size="md"
            onClick={handleExport}
            loading={exporting}
            disabled={!data}
            data-testid={`${TEST_ID}-export`}
          >
            <i className="fas fa-file-excel" style={{ marginRight: 6 }} />
            Xuất Excel
          </Button>
          <Button variant="secondary" size="md" onClick={() => window.location.reload()}>
            <i className="fas fa-sync-alt" style={{ marginRight: 6 }} />
            Làm mới
          </Button>
        </div>
      </div>

      {data && data.gapWeeks > 0 && (
        <AlertBanner
          type="warning"
          message={`Có ${data.gapWeeks}/13 tuần có khoảng trống tài trợ. Khoảng trống lớn nhất: ${fVndCompact(data.maxFundingGap)}.`}
        />
      )}

      {summaryCards}
      {chart}
      {weeklyTable}
    </div>
  );
};

export default ThirteenWeekCashflowPage;
